var counted = 0;

// Go Down
$(function () {
  $(".goDown").on("click", function (e) {
    e.preventDefault();
    $("html, body").animate(
      { scrollTop: $($(this).attr("href")).offset().top },
      500,
      "linear"
    );
  });
});

const rolebackButton = document.getElementsByClassName("roleback")[0];
if (window.innerWidth <= 767) {
  // Add the #banner-form ID
  if (rolebackButton) {
    rolebackButton.setAttribute("href", "lp/publishing1/#banner-form");
  }
} else {
  // Remove the #banner-form ID
  if (rolebackButton) {
    rolebackButton.removeAttribute("href", "lp/publishing1/#banner-form");
    // Page RoleBack to Top
    $(document).ready(function () {
      $(".roleback").click(function () {
        $("html, body").animate({ scrollTop: 0 }, 800);
        return false;
      });
    });
  }
}

window.addEventListener("load", function(event) {
  VirtualSelect.init({
      ele: '.virtual-select'
  });

});

function serviceFormServices() {
  if ($('#serviceForm input[name="data[service][]"]:checked').length > 0) {
      $('#serviceForm input[name="data[service][]"]').prop('required', false);
      $('#serviceForm .servicesList').css('border-color', '#8282824f');
      return true;
  } else {
      $('#serviceForm .servicesList').css('border-color', 'red');
      $('#serviceForm input[name="data[service][]"]').prop('required', true);
      return false;
  }
}



function contactFormServices() {
  if ($('#contactForm input[name="data[service][]"]:checked').length > 0) {
      $('#contactForm input[name="data[service][]"]').prop('required', false);
      $('#contactService .accordion-button').css('border', '');
      return true;
  } else {
      $('#contactService .accordion-button').css('border', '2px solid red');
      $('#contactForm input[name="data[service][]"]').prop('required', true);
      return false;
  }
}


$('#serviceForm input[name="data[service][]"]').on('change', serviceFormServices);
$('#contactForm input[name="data[service][]"]').on('change', contactFormServices);

$('#serviceForm').submit(function(e) {
  e.preventDefault();
  if (serviceFormServices()) {
      this.submit();
  }
});



$('#contactForm').submit(function(e) {
  e.preventDefault();
  if (contactFormServices()) {
      this.submit();
  }
});
$('.popUpBtn').click(function(){
    
  $('#getQuote').modal('show')
  var priceText = $(this).parents('.card').find('.card-title').text();
  var titleText = $(this).parents('.card').find('.card-text p').text();
  // alert(priceText + titleText)
  $('#getQuote input[name="price"]').val(priceText);
  $('#getQuote input[name="title"]').val(titleText);
  
  $('.close').click(function(){
      $('#getQuote').modal('hide');
  })

});